1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface Incident {
19	  cause: string;
20	  damages: Damage[];
21	}
22	
23	interface ClaimStep {
24	  op: "claim";
25	  policy: number;
26	  incident: Incident;
27	}
28	
29	type Step = QuoteStep | ClaimStep;
30	
31	interface Customer {
32	  yearsWithMHPCO: number;
33	}
34	
35	interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	const COMPONENT_PREMIUM = 25;
41	const BLOCK_SIZE = 3;
42	const BLOCK_PREMIUM = 60;
43	
44	const MAIN_ITEM_PREMIUM: Record<string, number> = {
45	  sword: 100,
46	  amulet: 60,
47	  staff: 80,
48	  potion: 40,
49	};
50	
51	const INSURANCE_VALUE: Record<string, number> = {
52	  sword: 1000,
53	  amulet: 600,
54	  staff: 800,
55	  potion: 400,
56	  rune: 250,
57	  moonstone: 250,
58	};
59	
60	const DEDUCTIBLE = 100;
61	const CAP_MULTIPLIER = 2;
62	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
63	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
64	
65	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
66	const CURSE_SURCHARGE_RATE = 0.5;
67	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
68	const HIGH_ENCHANTMENT_THRESHOLD = 5;
69	const LOYALTY_DISCOUNT_RATE = 0.2;
70	const LOYALTY_YEARS_THRESHOLD = 2;
71	const FOLLOWUP_DISCOUNT_RATE = 0.15;
72	const PROCESSING_FEE = 5;
73	const ROUNDING_PRECISION = 6;
74	
75	const roundTo = (value: number, direction: "up" | "down"): number => {
76	  const fixed = Number(value.toFixed(ROUNDING_PRECISION));
77	  return direction === "up" ? Math.ceil(fixed) : Math.floor(fixed);
78	};
79	
80	const componentBasePremium = (count: number): number => {
81	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
82	  return count * COMPONENT_PREMIUM;
83	};
84	
85	const COMPONENT_TYPES = ["rune", "moonstone"];
86	
87	const KNOWN_TYPES = [...Object.keys(MAIN_ITEM_PREMIUM), ...COMPONENT_TYPES];
88	
89	const validateKnownTypes = (items: Item[]): void => {
90	  for (const item of items) {
91	    if (!KNOWN_TYPES.includes(item.type)) {
92	      throw new Error(`unknown item type: ${item.type}`);
93	    }
94	  }
95	};
96	
97	const tally = (types: string[]): Map<string, number> => {
98	  const counts = new Map<string, number>();
99	  for (const type of types) {
100	    counts.set(type, (counts.get(type) ?? 0) + 1);
101	  }
102	  return counts;
103	};
104	
105	const countComponentsByType = (items: Item[]): Map<string, number> =>
106	  tally(
107	    items.map((item) => item.type).filter((type) => COMPONENT_TYPES.includes(type)),
108	  );
109	
110	const componentsBasePremium = (items: Item[]): number => {
111	  const counts = [...countComponentsByType(items).values()];
112	  return counts.reduce((total, count) => total + componentBasePremium(count), 0);
113	};
114	
115	const itemBasePremium = (item: Item): number => MAIN_ITEM_PREMIUM[item.type] ?? 0;
116	
117	const mainItemsBasePremium = (items: Item[]): number =>
118	  items.reduce((total, item) => total + itemBasePremium(item), 0);
119	
120	const policyBasePremium = (items: Item[]): number =>
121	  mainItemsBasePremium(items) + componentsBasePremium(items);
122	
123	const isHighEnchantment = (item: Item): boolean =>
124	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
125	
126	const itemSurcharge = (item: Item): number => {
127	  const base = itemBasePremium(item);
128	  const curse = item.cursed ? CURSE_SURCHARGE_RATE * base : 0;
129	  const highEnchant = isHighEnchantment(item)
130	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE * base
131	    : 0;
132	  return curse + highEnchant;
133	};
134	
135	const itemSurcharges = (items: Item[]): number =>
136	  items.reduce((total, item) => total + itemSurcharge(item), 0);
137	
138	const isLoyalCustomer = (customer: Customer): boolean =>
139	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
140	
141	const loyaltyDiscount = (base: number, customer: Customer): number =>
142	  isLoyalCustomer(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
143	
144	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
145	  isFollowUp ? base * FOLLOWUP_DISCOUNT_RATE : 0;
146	
147	const quotePremium = (
148	  items: Item[],
149	  customer: Customer,
150	  isFollowUp: boolean,
151	): number => {
152	  validateKnownTypes(items);
153	  const base = policyBasePremium(items);
154	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
155	  const total =
156	    base +
157	    itemSurcharges(items) +
158	    firstInsurance -
159	    loyaltyDiscount(base, customer) -
160	    followUpDiscount(base, isFollowUp) +
161	    PROCESSING_FEE;
162	  return roundTo(total, "up");
163	};
164	
165	const insuranceSum = (items: Item[]): number =>
166	  items.reduce((total, item) => total + (INSURANCE_VALUE[item.type] ?? 0), 0);
167	
168	const reimbursement = (amount: number, insuredItem: Item): number =>
169	  (insuredItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
170	    ? HIGH_ENCHANTMENT_PAYOUT_RATE * amount
171	    : amount;
172	
173	const damagePayout = (damage: Damage, insuredItem: Item): number =>
174	  reimbursement(damage.amount, insuredItem) - DEDUCTIBLE;
175	
176	const payoutForDamage = (damage: Damage, items: Item[]): number => {
177	  const insuredItem = items.find((item) => item.type === damage.itemType) as Item;
178	  return damagePayout(damage, insuredItem);
179	};
180	
181	const incidentPayout = (incident: Incident, items: Item[]): number =>
182	  incident.damages.reduce(
183	    (total, damage) => total + payoutForDamage(damage, items),
184	    0,
185	  );
186	
187	const initialCap = (items: Item[]): number =>
188	  CAP_MULTIPLIER * insuranceSum(items);
189	
190	const validateDamageCounts = (incident: Incident, items: Item[]): void => {
191	  const insured = tally(items.map((item) => item.type));
192	  const damaged = tally(incident.damages.map((damage) => damage.itemType));
193	  for (const [type, count] of damaged) {
194	    if (count > (insured.get(type) ?? 0)) {
195	      throw new Error(`claim references more ${type} than insured`);
196	    }
197	  }
198	};
199	
200	const claimResult = (
201	  step: ClaimStep,
202	  scenario: Scenario,
203	  remainingCapByPolicy: Map<number, number>,
204	): { payout: number; remainingCap: number } => {
205	  const policy = scenario.steps[step.policy] as QuoteStep;
206	  validateDamageCounts(step.incident, policy.items);
207	  const remainingCap =
208	    remainingCapByPolicy.get(step.policy) ?? initialCap(policy.items);
209	  const rawPayout = incidentPayout(step.incident, policy.items);
210	  const payout = roundTo(Math.min(rawPayout, remainingCap), "down");
211	  const newRemainingCap = remainingCap - payout;
212	  remainingCapByPolicy.set(step.policy, newRemainingCap);
213	  return { payout, remainingCap: newRemainingCap };
214	};
215	
216	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
217	  let quoteCount = 0;
218	  const remainingCapByPolicy = new Map<number, number>();
219	  const results = scenario.steps.map((step) => {
220	    if (step.op === "claim") {
221	      return claimResult(step, scenario, remainingCapByPolicy);
222	    }
223	    const isFollowUp = quoteCount > 0;
224	    quoteCount += 1;
225	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
226	  });
227	  return { results };
228	};
